sections.content:
An extension function is a function defined outside a class but called as if it were a member of that class. It allows you to extend a class with new abilities without modifying its source code.

Syntax:
fun ReceiverType.functionName(arguments): ReturnType { ... }

sections.code:
// Extending the String class
fun String.removeSpaces(): String {
    return this.replace(" ", "")
}

val text = "Hello Kotlin World"
println(text.removeSpaces())

// Define the extensions
fun View.hide() {
    this.visibility = View.GONE
}

fun View.show() {
    this.visibility = View.VISIBLE
}

// Usage in Activity
binding.progressBar.show()
binding.errorText.hide()

val String.isEmail: Boolean
    get() = contains("@") && contains(".")

if ("user@mail.com".isEmail) {
    // Proceed
}

// 1. Toast Extension
fun Context.toast(message: String) {
    Toast.makeText(this, message, Toast.LENGTH_SHORT).show()
}

// 2. Fragment Navigation Extension
fun Fragment.navigateTo(fragment: Fragment) {
    parentFragmentManager.beginTransaction()
        .replace(R.id.container, fragment)
        .commit()
}

// 3. String to Date
fun String.toDate(format: String): Date? {
    return SimpleDateFormat(format, Locale.getDefault()).parse(this)
}
